'use strict';

// MODULES //

import isnan from '@stdlib/math-base-assert-is-nan';


// VARIABLES //

var STDEV_CONST = 0.3418336950449515; // sqrt( (π²/16) - (1/2) )


// MAIN //

/**
* Returns the standard deviation for an anglit distribution with location parameter `mu` and scale parameter `sigma`.
*
* @param {number} mu - location parameter
* @param {PositiveNumber} sigma - scale parameter
* @returns {PositiveNumber} standard deviation
*
* @example
* var y = stdev( 0.0, 1.0 );
* // returns ~0.342
*
* @example
* var y = stdev( 2.0, 4.0 );
* // returns ~1.367
*
* @example
* var y = stdev( NaN, 1.0 );
* // returns NaN
*
* @example
* var y = stdev( 0.0, NaN );
* // returns NaN
*
* @example
* var y = stdev( 0.0, 0.0 );
* // returns NaN
*/
function stdev( mu, sigma ) {
	if (
		isnan( mu ) ||
		isnan( sigma ) ||
		sigma <= 0.0
	) {
		return NaN;
	}
	return sigma * STDEV_CONST;
}


// EXPORTS //

export default stdev;
